"""
Represents a Checkers board (8x8).
"""

class Board:
    def __init__(self):
        self.grid = [[None] * 8 for _ in range(8)]
        self.init_board()

    def init_board(self):
        # Initialize the board with pieces
        colors = ['r', 'b']
        for row, color in zip(range(3), colors):
            for col in range(row % 2, 8, 2):
                self.grid[row][col] = Piece(color)
        for row, color in zip(range(5, 8), colors[::-1]):
            for col in range((row + 1) % 2, 8, 2):
                self.grid[row][col] = Piece(color)

    def print_board(self):
        for row in self.grid:
            for cell in row:
                if cell is None:
                    print('.', end=' ')
                else:
                    print(cell, end=' ')
            print()

    def move_piece(self, from_pos, to_pos):
        piece = self.grid[from_pos[0]][from_pos[1]]
        if piece is not None:
            self.grid[from_pos[0]][from_pos[1]] = None
            self.grid[to_pos[0]][to_pos[1]] = piece
            return True
        return False

class Piece:
    def __init__(self, color):
        self.color = color
        self.is_king = False

    def __str__(self):
        if self.is_king:
            return f'{self.color}K'
        return self.color
```

