"""
Manages the game state and flow.
"""

from board import Board, Piece

class GameManager:
    def __init__(self):
        self.board = Board()
        self.current_player = 'r'

    def play_move(self, from_pos, to_pos):
        if not self.board.move_piece(from_pos, to_pos):
            return False
        # Check for capturing and kinging rules here
        # For simplicity, we'll just switch players
        self.current_player = 'b' if self.current_player == 'r' else 'r'
        return True

    def is_game_over(self):
        # Simple check to see if one player has no pieces left
        piece_count = {'r': 0, 'b': 0}
        for row in range(8):
            for col in range(8):
                piece = self.board.grid[row][col]
                if piece:
                    piece_count[piece.color] += 1
        return piece_count['r'] == 0 or piece_count['b'] == 0

    def print_board(self):
        self.board.print_board()

def run_game():
    game_manager = GameManager()
    while not game_manager.is_game_over():
        game_manager.print_board()
        move = input(f"Player {game_manager.current_player}, enter your move (e.g., 3,4 to 5,6): ")
        from_pos, to_pos = map(int, move.split(','))
        if not game_manager.play_move((from_pos, to_pos), (to_pos + 2, to_pos + 1)):
            print("Invalid move. Try again.")
    game_manager.print_board()
    print(f"Player {game_manager.current_player} wins!")
```

